def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            priorities[i] = 0.0
            continue
        elif ratio < 0.3:
            score = (0.3 - ratio) ** 3 + 0.2
        elif ratio < 0.75:
            score = ((0.75 - ratio) ** 2) * 0.5
        else:
            score = abs(np.log(ratio)) * (1 + (i % 5) * 0.15)
        for offset in range(1, 6):
            prev_idx = i - offset
            next_idx = i + offset
            if prev_idx >= 0:
                neighbor_cap = bins[prev_idx]
                if neighbor_cap > 0:
                    diff = abs(capacity - neighbor_cap) / neighbor_cap
                    score += diff * (0.1 / offset)
                    ratio_diff = abs((item / neighbor_cap) - ratio)
                    if ratio_diff < 0.2:
                        score -= 0.05 / offset
            if next_idx < n:
                neighbor_cap = bins[next_idx]
                if neighbor_cap > 0:
                    diff = abs(capacity - neighbor_cap) / neighbor_cap
                    score += diff * (0.1 / offset)
                    ratio_diff = abs((item / neighbor_cap) - ratio)
                    if ratio_diff < 0.2:
                        score -= 0.05 / offset
        if score < 0:
            score = 0
        if capacity < item * 1.5:
            score *= 1.8
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        min_finite = np.min(finite_priorities)
        max_finite = np.max(finite_priorities)
        for i in range(n):
            if not np.isfinite(priorities[i]):
                priorities[i] = max_finite * 1.2
            elif priorities[i] < min_finite * 0.5:
                priorities[i] = min_finite * 0.5
    max_p = np.max(priorities)
    min_p = np.min(priorities)
    if max_p > min_p:
        priorities = (priorities - min_p) / (max_p - min_p)
    else:
        priorities = np.zeros_like(priorities)
    for i in range(n):
        count_smaller = 0
        for j in range(i+1, min(i+4, n)):
            if bins[j] < bins[i]:
                count_smaller += 1
            else:
                break
        if count_smaller >= 2:
            priorities[i] += 0.1 * count_smaller
            if priorities[i] > 1:
                priorities[i] = 1
    return priorities
